(139, 'id_typeform', 'Bruna Angelo Lima', 'bruna.angelo_lima@elancoah.com', 'ZlVEWC9wZ3JhUlAwNXRnNU5xbWNFUT09', 'mylene.silva@elancoah.com.', 'text', '', 'Mylene: seja muito bem vinda a equipe. Você já iniciou muito bem, demonstrando proatividade, humildade e entusiasmo. Fico muito feliz em poder tê-la conosco. Conte comigo para que você brilhe durante essa jornada. Beijos, Bruna.', 'response_type', '2026-02-24 05:02:44', '2026-02-24 05:02:44', '2026-02-24 05:02:44', 'network_id', 'tag', 'ending'),
